import pytest
from source import process_batch

def test_process_batch_includes_last_element():
    items = [1, 2, 3]
    result = process_batch(items)
    assert len(result) == len(items), (
        f"process_batch dropped the last element: expected length {len(items)}, got {len(result)}"
    )
    assert result == [2, 4, 6], (
        f"process_batch returned {result}, expected [2, 4, 6] — last element was skipped"
    )

def test_process_batch_single_element():
    result = process_batch([5])
    assert result == [10], (
        f"process_batch([5]) returned {result}, expected [10] — single-element list was skipped entirely"
    )
